import{j as a,b as l,c as e,aa as i}from"./chunks/framework.Bxf40uRC.js";const m=JSON.parse('{"title":"Go语言之垃圾回收","description":"","frontmatter":{},"headers":[],"relativePath":"Go/Go语言之垃圾回收.md","filePath":"Go/Go语言之垃圾回收.md","lastUpdated":null}'),o={name:"Go/Go语言之垃圾回收.md"},t=i('<h1 id="go语言之垃圾回收" tabindex="-1">Go语言之垃圾回收 <a class="header-anchor" href="#go语言之垃圾回收" aria-label="Permalink to &quot;Go语言之垃圾回收&quot;">​</a></h1><h2 id="三色标记法" tabindex="-1">三色标记法 <a class="header-anchor" href="#三色标记法" aria-label="Permalink to &quot;三色标记法&quot;">​</a></h2><h3 id="简单规则" tabindex="-1">简单规则 <a class="header-anchor" href="#简单规则" aria-label="Permalink to &quot;简单规则&quot;">​</a></h3><ol><li>黑白灰三种颜色；</li><li>黑对象代表自身存活，其指向的对象都标记完成；</li><li>灰对象代表自身存活，指向对象还未被标记；</li><li>白对象代表，未被标记到的对象，可能是垃圾对象；</li><li>标记开始前，从根对象(全局对象、栈上的局部变量)置黑，将其所指向的对象置灰色；</li><li>标记期间，从灰色对象出发，向其所指向的对象置灰，然后本身置黑；</li><li>标记结束，白色就是不可达对象，进行清扫；</li></ol><h4 id="缺点" tabindex="-1">缺点 <a class="header-anchor" href="#缺点" aria-label="Permalink to &quot;缺点&quot;">​</a></h4><ol><li>每次垃圾回收都需要STW，影响用户体验</li></ol><h2 id="并发垃圾回收" tabindex="-1">并发垃圾回收 <a class="header-anchor" href="#并发垃圾回收" aria-label="Permalink to &quot;并发垃圾回收&quot;">​</a></h2><p>允许用户协程和GC协程并发运行，速度快，用户体验良好</p><h3 id="缺点-1" tabindex="-1">缺点 <a class="header-anchor" href="#缺点-1" aria-label="Permalink to &quot;缺点&quot;">​</a></h3><h3 id="_1-漏标问题" tabindex="-1">1. 漏标问题 <a class="header-anchor" href="#_1-漏标问题" aria-label="Permalink to &quot;1. 漏标问题&quot;">​</a></h3><p>存在对象未被标记问题，导致误删，造成不可逆转问题</p><img src="https://s2.loli.net/2024/04/08/h87RQn1qXe2LAUV.png" alt="image-20240408201815093" style="zoom:67%;"><ol><li>B持有C的引用；</li><li>A扫描完成，置黑；B是灰色，未完成扫描；</li><li>用户协程，B删除对于C的引用，A添加对于C的引用；</li><li>C无法被标记，然后被删除，造成问题；</li></ol><h3 id="_2-多标问题" tabindex="-1">2. 多标问题 <a class="header-anchor" href="#_2-多标问题" aria-label="Permalink to &quot;2. 多标问题&quot;">​</a></h3><img src="https://s2.loli.net/2024/04/08/8rbKBUW6e3RChkZ.png" alt="image-20240408202023391" style="zoom:67%;"><ol><li>A持有对B的引用，A置黑，B灰；</li><li>A删除对于B的引用，B不会被删除；</li><li>会在下一轮的时候，进行删除，浮动垃圾；</li></ol><h2 id="屏障机制" tabindex="-1">屏障机制 <a class="header-anchor" href="#屏障机制" aria-label="Permalink to &quot;屏障机制&quot;">​</a></h2><p>主要为了解决漏标问题，提出了屏障机制</p><h3 id="_1-强弱三色不变式" tabindex="-1">1. 强弱三色不变式 <a class="header-anchor" href="#_1-强弱三色不变式" aria-label="Permalink to &quot;1. 强弱三色不变式&quot;">​</a></h3><p>漏标的主要存在原因是：</p><ol><li>黑色对象指向了白色对象； <ul><li><strong>强三色不变式</strong>：白色对象不能被黑色对象引用；</li></ul></li><li>灰色，白色对象删除了白色对象； <ul><li><strong>弱三色不变式</strong>：白色对象可以被黑色对象引用，但是要能通过灰色对象到达；</li></ul></li><li>1发生在2之前；</li></ol><h3 id="_2-插入写屏障" tabindex="-1">2. 插入写屏障 <a class="header-anchor" href="#_2-插入写屏障" aria-label="Permalink to &quot;2. 插入写屏障&quot;">​</a></h3><p>直接破坏1，因为1的问题主要出现在黑色引用了白色，导致白色无法被标记，然后被回收，出现了问题；</p><p>在黑色引用白色时候，出发屏障，将白色置为灰色，问题解决</p><h3 id="_3-删除写屏障" tabindex="-1">3. 删除写屏障 <a class="header-anchor" href="#_3-删除写屏障" aria-label="Permalink to &quot;3. 删除写屏障&quot;">​</a></h3><p>直接破坏2，因为2的问题出现在，灰色删除对于白色的引用，导致白色不能被标记，容易被误删，出现了问题；</p><p>在灰色删除白色的时候，直接将该对象置为灰色，问题解决；</p><h3 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h3><ol><li>屏障无法作用于栈对象，因为栈的变化比较快，容易造成额外的资源开销；</li><li>如果屏障无法作用于栈对象，那么就会出现上述的问题，在栈中出现漏标的问题；</li></ol><h3 id="_4-混合写屏障" tabindex="-1">4. 混合写屏障 <a class="header-anchor" href="#_4-混合写屏障" aria-label="Permalink to &quot;4. 混合写屏障&quot;">​</a></h3><ol><li>GC开始之前，将栈为单位分批置黑；</li><li>GC期间，栈上的对象直接置黑；</li><li>堆对象正常启用插入写屏障和删除写屏障；</li></ol><h2 id="case探讨" tabindex="-1">case探讨 <a class="header-anchor" href="#case探讨" aria-label="Permalink to &quot;case探讨&quot;">​</a></h2><p>主要讨论极端情况下，混合写屏障为什么能够一一解决问题？</p><h3 id="case-1" tabindex="-1">case 1 <a class="header-anchor" href="#case-1" aria-label="Permalink to &quot;case 1&quot;">​</a></h3><p>背景介绍：A在栈中，C是堆白色对象，B是堆中灰色对象，B指向C；</p><p>moment1：A建立对于C的引用；</p><p>moment2：B删除对于B的引用；</p><p>这个对应于上述说的漏标的1，2顺序；但是这个不会出现危险情况</p><ul><li>虽然A建立对于C的引用本身应该执行插入写屏障的，但是由于A是栈对象，失效；</li><li>B删除C的引用，会将C置灰；</li></ul><h3 id="case-2" tabindex="-1">case 2 <a class="header-anchor" href="#case-2" aria-label="Permalink to &quot;case 2&quot;">​</a></h3><p>背景介绍：A(灰色)，B(黑色)是栈对象，C是堆对象；</p><p>moment1：B建立对于C的引用；</p><p>moment2：A删除对于C的引用；</p><p>这个对应于上述说的漏标的1，2顺序；但是这个不会出现危险情况</p><ul><li>乍一看，删除写屏障和插入写屏障都失效了，但是不会出现漏标的危害；因为这种情况根本就不存在，因为B不可能存在C的引用；</li><li>B本身持有C的引用，那么C已经是灰色了(x)</li><li>B持有A的引用，通过A间接找到C，不可能，因为逃逸分析，B不可能持有对于另一个栈的引用；</li><li>B同一个栈内的存在其他X能够到达C，X能够到达C，C不用被担心无法被标记；</li></ul>',45),r=[t];function h(n,s,c,d,p,u){return l(),e("div",null,r)}const b=a(o,[["render",h]]);export{m as __pageData,b as default};
